---战斗日志
-----------------------------------------------------------------
---@class LFightLogCtrl
local LFightLogCtrl = LxClass("LFightLogCtrl",nil)
------------------------------------------------------------------
function LFightLogCtrl:LFightLogCtrl(battleUnit)
	---@type LFightUnit
	self._battleUnit = battleUnit

	self._tblHpRecord = {}

	self._splitStr = "-----------------------------------------------------------------"

	self._isLogOpen = true and LOG_INFO_ENABLED
end

function LFightLogCtrl:IsLogOpen()
	return self._isLogOpen
end

function LFightLogCtrl:LogNormal(str)
	if not self:IsLogOpen() then return end
	LXFW.Info("[battle] "..tostring(str))
end

function LFightLogCtrl:LogError(str)
	if not self:IsLogOpen() then return end
	printErrorN("[battle] "..tostring(str))
end

function LFightLogCtrl:LogHpChange(id,maHp,nowHP,oldHp,changeHp)
	if not self:IsLogOpen() then return end

	table.insert(self._tblHpRecord,
			string.format("%s : max=%s , (%s + %s -> %s)",
					tostring(id),tostring(maHp),tostring(oldHp),tostring(changeHp),tostring(nowHP)
			)
	)
end

function LFightLogCtrl:SaveHpLog()
	if not self:IsLogOpen() then return end
	if (not CS.IsUnityEdit()) then
		return
	end
	local reportData = self._battleUnit:GetReportData()
	local reportId = reportData:GetReportId()

	local filePath = CS.AppPersistentDataPath().."fightlog/hp_"..reportId..".log"
	local contents = table.concat(self._tblHpRecord,"\n")
	CS.FileWriteText(filePath, contents)
end

function LFightLogCtrl:LogHpFinal(formationA,formationB)
	if not self:IsLogOpen() then return end

	table.insert(self._tblHpRecord,self._splitStr)
	table.insert(self._tblHpRecord,"")
	table.insert(self._tblHpRecord,"formationA")
	for k,v in ipairs(formationA) do
		table.insert(self._tblHpRecord,v:ToHpString())
	end

	table.insert(self._tblHpRecord,"")
	table.insert(self._tblHpRecord,"formationB")
	for k,v in ipairs(formationB) do
		table.insert(self._tblHpRecord,v:ToHpString())
	end
end

-----------------------------------------------------------------
return LFightLogCtrl